// ============================================
// Extract clusters from parsed RSS feed
// ============================================
try {
  const input = $input.first().json;
  let items = input.data?.rss?.channel?.item || input.rss?.channel?.item || [];
  if (!Array.isArray(items)) items = [items];
  const feedTitle = input.data?.rss?.channel?.title || input.rss?.channel?.title || 'Google Tin tức';
  const lastBuildDate = input.data?.rss?.channel?.lastBuildDate || input.rss?.channel?.lastBuildDate || '';
  function toGMT7(dateStr) {
    if (!dateStr) return '';
    try {
      const d = new Date(dateStr);
      d.setHours(d.getHours() + 7);
      return d.toLocaleString('vi-VN', { weekday: 'short', year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit', timeZone: 'UTC' }) + ' (GMT+7)';
    } catch(e) { return dateStr; }
  }
  function parseDescription(html) {
    if (!html) return [];
    const articles = [];
    const liRegex = /<a\s+href="([^"]+)"[^>]*>([^<]+)<\/a>\s*(?:&nbsp;)*\s*<font[^>]*>([^<]+)<\/font>/gi;
    let match;
    while ((match = liRegex.exec(html)) !== null) {
      articles.push({ link: match[1], title: match[2].trim(), source: match[3].trim() });
    }
    if (articles.length === 0) {
      const simpleRegex = /<a\s+href="([^"]+)"[^>]*>([^<]+)<\/a>/gi;
      while ((match = simpleRegex.exec(html)) !== null) {
        if (!match[2].includes('Xem Th')) {
          articles.push({ link: match[1], title: match[2].trim(), source: '' });
        }
      }
    }
    return articles.slice(0, 5);
  }
  function parseTitle(title) {
    if (!title) return { headline: '', source: '' };
    const lastDash = title.lastIndexOf(' - ');
    if (lastDash > 0) return { headline: title.substring(0, lastDash).trim(), source: title.substring(lastDash + 3).trim() };
    return { headline: title, source: '' };
  }
  const clusters = items.map((item, idx) => {
    const parsed = parseTitle(item.title || '');
    const sourceTag = item.source;
    const sourceUrl = typeof sourceTag === 'object' ? (sourceTag.url || '') : '';
    const sourceName = typeof sourceTag === 'object' ? (sourceTag._ || sourceTag['#text'] || sourceTag.$t || '') : (sourceTag || '');
    return {
      index: idx, headline: parsed.headline, mainSource: sourceName || parsed.source,
      mainSourceUrl: sourceUrl, mainLink: item.link || '', pubDate: item.pubDate || '',
      pubDateGMT7: toGMT7(item.pubDate),
      guid: (typeof item.guid === 'object') ? (item.guid._ || item.guid['#text'] || item.guid.$t || JSON.stringify(item.guid)) : (item.guid || ''),
      relatedArticles: parseDescription(item.description || '')
    };
  });
  return [{ json: { feedTitle, lastBuildDate, lastBuildDateGMT7: toGMT7(lastBuildDate), totalClusters: clusters.length, clusters } }];
} catch (error) {
  return [{ json: { error: true, message: error.message, feedTitle: 'Google Tin tức', totalClusters: 0, clusters: [] } }];
}

const input = $input.first().json;
if (input.error || !input.clusters) return [$input.first()];
const BATCH_SIZE = 8;
const clusters = input.clusters;
const batches = [];
for (let i = 0; i < clusters.length; i += BATCH_SIZE) {
  batches.push({
    json: {
      batchIndex: Math.floor(i / BATCH_SIZE),
      clusters: clusters.slice(i, i + BATCH_SIZE),
      _meta: {
        feedTitle: input.feedTitle, lastBuildDate: input.lastBuildDate,
        lastBuildDateGMT7: input.lastBuildDateGMT7, totalClusters: input.totalClusters,
        totalBatches: Math.ceil(clusters.length / BATCH_SIZE)
      }
    }
  });
}
return batches;

// Flatten all Google News URLs from batch clusters into individual items
const batch = $input.first().json;
const clusters = batch.clusters || [];
const items = [];

for (const cluster of clusters) {
  if (cluster.mainLink) {
    items.push({
      json: {
        link: cluster.mainLink,
        _clusterIndex: cluster.index,
        _type: 'main'
      }
    });
  }
  if (cluster.relatedArticles) {
    for (let i = 0; i < cluster.relatedArticles.length; i++) {
      const art = cluster.relatedArticles[i];
      if (art.link) {
        items.push({
          json: {
            link: art.link,
            _clusterIndex: cluster.index,
            _type: 'related',
            _relatedIndex: i
          }
        });
      }
    }
  }
}

// Pass batch metadata in first item
if (items.length > 0) {
  items[0].json._batch = batch;
}

return items;

// Rebuild clusters with decoded URLs
const items = $input.all();
let batch = null;
const resolvedMap = {};

for (const item of items) {
  const data = item.json;
  if (data._batch) {
    batch = data._batch;
  }
  if (data.link && data.decodedUrl) {
    resolvedMap[data.link] = data.decodedUrl;
  }
}

if (!batch) {
  // Fallback: get batch from Flatten URLs node
  const flattenItems = $('Flatten URLs').all();
  for (const item of flattenItems) {
    if (item.json._batch) {
      batch = item.json._batch;
      break;
    }
  }
}

if (!batch) {
  return [{ json: { error: true, message: 'No batch data found' } }];
}

const clusters = batch.clusters || [];
for (const cluster of clusters) {
  if (resolvedMap[cluster.mainLink]) {
    cluster.mainLinkResolved = resolvedMap[cluster.mainLink];
  }
  if (cluster.relatedArticles) {
    for (const art of cluster.relatedArticles) {
      if (resolvedMap[art.link]) {
        art.resolvedLink = resolvedMap[art.link];
      }
    }
  }
}

return [{
  json: {
    ...batch,
    clusters,
    resolvedCount: Object.keys(resolvedMap).length,
    totalLinks: items.length
  }
}];

// ============================================
// Merge All Batches: Gom tất cả batch đã resolve
// thành 1 object duy nhất trước khi AI classify
// ============================================
const items = $input.all();
const allClusters = [];
let meta = {};
let totalResolved = 0;
let totalLinks = 0;

for (const item of items) {
  const data = item.json;
  if (data.clusters && Array.isArray(data.clusters)) {
    allClusters.push(...data.clusters);
  }
  if (data._meta) {
    meta = data._meta;
  }
  totalResolved += (data.resolvedCount || 0);
  totalLinks += (data.totalLinks || 0);
}

// Sắp xếp lại theo index gốc
allClusters.sort((a, b) => a.index - b.index);

return [{
  json: {
    feedTitle: meta.feedTitle || 'Google Tin tức',
    lastBuildDate: meta.lastBuildDate || '',
    lastBuildDateGMT7: meta.lastBuildDateGMT7 || '',
    totalClusters: allClusters.length,
    clusters: allClusters,
    resolvedCount: totalResolved,
    totalLinks: totalLinks
  }
}];

// ============================================
// PrepareInput: Extract headlines for AI classification
// ============================================
const input = $input.first().json;
const clusters = input.clusters || [];
const headlineList = clusters.map(c => ({ i: c.index, h: c.headline }));
return [{ json: { headlineList, fullData: input } }];

// ============================================
// BuildTelegramMessage: Tách tin theo Topic
// ============================================
const READER_PREFIX = 'https://ggnews-reader.23000568.workers.dev/';
const MAX_LEN = 4096;
const aiNode = $('AI Classify Topics').first().json;
const prepNode = $('PrepareInput').first().json;
const fullData = prepNode.fullData;
const clusters = fullData.clusters || [];
const buildDate = fullData.lastBuildDateGMT7 || '';
let aiOutput;
try {
  const raw = aiNode.message?.content || aiNode.choices?.[0]?.message?.content || JSON.stringify(aiNode);
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  aiOutput = JSON.parse(cleaned);
} catch (e) {
  aiOutput = [{ topic: '📰 TIN TỨC', indices: clusters.map(c => c.index) }];
}
function esc(text) { return String(text || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;'); }
function makeLink(source, resolvedLink) {
  if (!resolvedLink) return '<i>' + esc(source) + '</i>';
  const url = READER_PREFIX + resolvedLink;
  return '<a href="' + url + '">' + esc(source) + '</a>';
}
const messages = [];
const header = '📰 <b>TIN TỨC NỔI BẬT</b>\n🕐 ' + esc(buildDate) + '\n\n';
for (let i = 0; i < aiOutput.length; i++) {
  const group = aiOutput[i];
  let currentMsg = i === 0 ? header : '';
  currentMsg += '<b>' + esc(group.topic) + '</b>\n\n';
  for (const idx of group.indices) {
    const cluster = clusters.find(c => c.index === idx);
    if (!cluster) continue;
    let itemText = '• <b>' + esc(cluster.headline) + '</b>\n';
    const sourceLinks = [];
    const seenUrls = new Set();
    if (cluster.mainLinkResolved && cluster.mainSource) {
      seenUrls.add(cluster.mainLinkResolved);
      sourceLinks.push(makeLink(cluster.mainSource, cluster.mainLinkResolved));
    }
    if (cluster.relatedArticles) {
      for (const art of cluster.relatedArticles) {
        const url = art.resolvedLink || '';
        if (!url || seenUrls.has(url)) continue;
        seenUrls.add(url);
        sourceLinks.push(makeLink(art.source, url));
      }
    }
    if (sourceLinks.length > 0) { itemText += '↳ ' + sourceLinks.join(' | ') + '\n\n'; }
    else { itemText += '\n'; }
    if ((currentMsg + itemText).length > MAX_LEN) {
      messages.push(currentMsg.trim());
      currentMsg = '<b>' + esc(group.topic) + ' (tiếp)</b>\n\n' + itemText;
    } else { currentMsg += itemText; }
  }
  if (currentMsg.trim()) messages.push(currentMsg.trim());
}
return messages.map((text, i) => ({ json: { text, parse_mode: 'HTML', part: i + 1, totalParts: messages.length } }));
